func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type trialRecord struct {
		assignIdx int
		costDelta float64
		success   bool
	}
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	// Randomize order processing to escape deterministic bad patterns
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	for _, orderPos := range orderIndices {
		jj := orderPos
		bestTrial := trialRecord{assignIdx: -1, costDelta: 1e18, success: false}
		// Try every existing assign (both empty and non‑empty)
		for ai := 0; ai < dispatch.AssignsLen || ai == dispatch.AssignsLen; ai++ {
			if ai == dispatch.AssignsLen && bestTrial.success {
				break // we already found a feasible existing route
			}
			// Save original state before trial
			originalCost := dispatch.Assigns[ai].Cost
			added := dispatch.Assigns[ai].AddShip(total_ship+jj, oris[jj], dess[jj])
			if added {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				delta := newCost - originalCost
				// Keep track of the best delta across trials
				if newCost >= 0 && delta < bestTrial.costDelta {
					bestTrial.assignIdx = ai
					bestTrial.costDelta = delta
					bestTrial.success = true
				}
				// Undo trial insertion
				dispatch.Assigns[ai].RemoveShip(total_ship + jj)
				dispatch.Assigns[ai].GenRoute()
			} else {
				// Failed insertion: restore cost explicitly (already failed)
				dispatch.Assigns[ai].Cost = originalCost
			}
		}
		// Commit the best feasible insertion found
		if bestTrial.success {
			targetAi := bestTrial.assignIdx
			dispatch.Assigns[targetAi].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[targetAi].GenRoute()
			// If we inserted into a brand‑new assign beyond current length, extend AssignsLen
			if targetAi >= dispatch.AssignsLen && targetAi < MAXASSIGNS {
				dispatch.AssignsLen = targetAi + 1
			}
		} else {
			// Fallback: create a fresh assign at first available slot
			fallbackIdx := dispatch.AssignsLen
			for ; fallbackIdx < MAXASSIGNS; fallbackIdx++ {
				// Use an empty assign (may already exist if previously created but unused)
				if fallbackIdx < dispatch.AssignsLen && dispatch.Assigns[fallbackIdx].Cost >= 0 {
